    """
    result = []
    if s and s[0].isspace():
        s = s[1:]
    if s and not s[0].isspace():
        for i in range(len(s) - n + 1):
            if s[i].isspace():
                break
            for j in range(i + 1, i + n):
                if s[j].isspace():
                    break
                if s[j].isupper():
                    break
                if s[j].islower():
                    break
                break
            else:
                result.append(s[i : i + n])
    return result

