def fix_spaces(text):
    """
    Given a string text, replace all spaces in it with underscores, 
    and if a string has more than 2 consecutive spaces, 
    then replace all consecutive spaces with - 

    fix_spaces("Example") == "Example"
    fix_spaces("Example 1") == "Example_1"
    fix_spaces(" Example 2") == "_Example_2"
    fix_spaces(" Example   3") == "_Example-3"
    """
    result = []
    count_consecutive_spaces = 0
    for letter in text:
        if letter == " ":
            count_consecutive_spaces += 1
        else:
            if count_consecutive_spaces!= 0:
                if count_consecutive_spaces == 1:
                    result.append(letter)
                elif count_consecutive_spaces == 2:
                    result.append(f"-{letter}")
                else:
                    result.append(f"-{('-' * (count_consecutive_spaces - 1))}-{letter}")
                count_consecutive_spaces = 0
            else:
                result.append(letter)
    return ''.join(result)

def fix_spaces(text):
    """
    Given a string text, replace all spaces in it with underscores, 
    and if a string has more than 2 consecutive spaces, 
    then replace all consecutive spaces with - 

    fix_spaces("Example") == "Example"
    fix_spaces("Example 1") == "Example_1"
    fix_spaces(" Example 2") == "_Example_2"
    fix_spaces(" Example   3") == "_Example-3"
    """
    new_text = []
    for letter in text:
        if letter == " ":
            new_text.append("_")
        else:
            new_text.append(letter)

    while 3 <= sum(1 for c in new_text if c == "_"):
        new_text = new_text[::2]

    return ''.join(new_text)

